// This is your Prisma schema file
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator client {
  provider = "prisma-client-js"
}

// ============================================================================
// USERS MODEL
// ============================================================================

model User {
  id        String   @id @default(cuid())
  email     String   @unique
  password  String   // bcrypt hash
  firstName String?
  lastName  String?
  avatarUrl String?

  role   Role   @default(USER)
  status Status @default(ACTIVE)

  createdAt  DateTime @default(now())
  updatedAt  DateTime @updatedAt
  lastLoginAt DateTime?

  // Relations
  createdTasks   Task[]              @relation("CreatedBy")
  assignedTasks  Task[]              @relation("AssignedTo")
  notifications  Notification[]
  auditLogs      AuditLog[]

  @@index([email])
  @@index([role])
  @@index([status])
  @@map("users")
}

enum Role {
  ADMIN
  MANAGER
  USER
  VIEWER
}

enum Status {
  ACTIVE
  INACTIVE
  SUSPENDED
}

// ============================================================================
// TASKS MODEL
// ============================================================================

model Task {
  id          String   @id @default(cuid())
  title       String
  description String?
  category    String?

  priority Priority @default(MEDIUM)
  status   TaskStatus @default(CREATED)

  // Assignment
  assigneeId String?
  assignee   User?      @relation("AssignedTo", fields: [assigneeId], references: [id], onDelete: SetNull)
  createdById String
  createdBy  User       @relation("CreatedBy", fields: [createdById], references: [id], onDelete: Cascade)

  // Dates
  createdAt   DateTime @default(now())
  updatedAt   DateTime @updatedAt
  deadline    DateTime?
  startedAt   DateTime?
  completedAt DateTime?

  // Time tracking
  estimatedHours Decimal? @db.Decimal(5, 2)
  actualHours    Decimal? @db.Decimal(5, 2)

  // Relations
  notifications Notification[]
  auditLogs     AuditLog[]

  @@index([assigneeId])
  @@index([status])
  @@index([deadline])
  @@index([createdAt])
  @@map("tasks")
}

enum Priority {
  LOW
  MEDIUM
  HIGH
  URGENT
}

enum TaskStatus {
  CREATED
  ASSIGNED
  IN_PROGRESS
  COMPLETED
  BLOCKED
}

// ============================================================================
// NOTIFICATIONS MODEL
// ============================================================================

model Notification {
  id    String @id @default(cuid())

  recipientId String
  recipient   User   @relation(fields: [recipientId], references: [id], onDelete: Cascade)

  taskId String?
  task   Task?   @relation(fields: [taskId], references: [id], onDelete: SetNull)

  type    NotificationType
  title   String
  message String?

  // Status
  readAt     DateTime?
  archivedAt DateTime?

  // Delivery channels
  emailSentAt DateTime?
  slackSentAt DateTime?

  createdAt DateTime @default(now())

  @@index([recipientId])
  @@index([readAt])
  @@index([type])
  @@map("notifications")
}

enum NotificationType {
  TASK_CREATED
  TASK_ASSIGNED
  DEADLINE_APPROACHING
  TASK_OVERDUE
  TASK_COMPLETED
}

// ============================================================================
// AUDIT LOGS MODEL
// ============================================================================

model AuditLog {
  id String @id @default(cuid())

  userId String
  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)

  entityType String  // 'task', 'user', etc
  entityId   String
  action     String  // 'create', 'update', 'delete'
  changes    Json    // Before/after values

  ipAddress String?
  userAgent String?

  createdAt DateTime @default(now())

  @@index([userId])
  @@index([entityType, entityId])
  @@index([createdAt])
  @@map("audit_logs")
}

// ============================================================================
// ANALYTICS SNAPSHOTS (Optional - for reporting)
// ============================================================================

model AnalyticsSnapshot {
  id   String @id @default(cuid())
  date DateTime @unique @db.Date

  totalTasks           Int
  completedTasks       Int
  overdueeTasks        Int
  averageCompletionTime String? // ISO 8601 duration

  userMetrics Json // By-user breakdown

  createdAt DateTime @default(now())

  @@map("analytics_snapshots")
}

