import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';
import { RegisterInput, LoginInput } from '../schemas/auth.schema';
import { JWTPayload, AuthResponse } from '../types/auth.types';

const JWT_SECRET = process.env.JWT_SECRET || 'dev-secret-key';
const JWT_EXPIRY = process.env.JWT_EXPIRY || '24h';
const REFRESH_TOKEN_EXPIRY = process.env.REFRESH_TOKEN_EXPIRY || '7d';
const BCRYPT_ROUNDS = 12;

// Mock user database (será substituído por Prisma)
const users: Map<string, any> = new Map();

export class AuthService {
  /**
   * Hash senha com bcrypt
   */
  static async hashPassword(password: string): Promise<string> {
    return bcrypt.hash(password, BCRYPT_ROUNDS);
  }

  /**
   * Comparar senha com hash
   */
  static async verifyPassword(password: string, hash: string): Promise<boolean> {
    return bcrypt.compare(password, hash);
  }

  /**
   * Gerar tokens JWT (access + refresh)
   */
  static generateTokens(userId: string, email: string, role: string) {
    const payload: JWTPayload = {
      id: userId,
      email,
      role: role as any,
    };

    const access_token = jwt.sign(payload, JWT_SECRET, {
      expiresIn: JWT_EXPIRY,
    });

    const refresh_token = jwt.sign(
      { id: userId, type: 'refresh' },
      JWT_SECRET,
      { expiresIn: REFRESH_TOKEN_EXPIRY }
    );

    return { access_token, refresh_token };
  }

  /**
   * Verificar e decodificar JWT
   */
  static verifyToken(token: string): JWTPayload | null {
    try {
      const decoded = jwt.verify(token, JWT_SECRET) as JWTPayload;
      return decoded;
    } catch (error) {
      return null;
    }
  }

  /**
   * Registrar novo usuário
   */
  static async register(data: RegisterInput) {
    const { email, password, firstName, lastName } = data;

    // Verificar se usuário já existe
    const existingUser = Array.from(users.values()).find(
      (u) => u.email === email
    );
    if (existingUser) {
      throw new Error('Email já registrado');
    }

    // Hash senha
    const passwordHash = await this.hashPassword(password);

    // Criar usuário
    const userId = `user_${Date.now()}`;
    const user = {
      id: userId,
      email,
      password: passwordHash,
      firstName,
      lastName,
      role: 'user',
      createdAt: new Date(),
    };

    users.set(userId, user);

    // Gerar tokens
    const { access_token, refresh_token } = this.generateTokens(
      userId,
      email,
      'user'
    );

    return {
      access_token,
      refresh_token,
      user: {
        id: userId,
        email,
        firstName,
        lastName,
        role: 'user',
      },
    } as AuthResponse;
  }

  /**
   * Fazer login
   */
  static async login(data: LoginInput) {
    const { email, password } = data;

    // Encontrar usuário
    const user = Array.from(users.values()).find((u) => u.email === email);
    if (!user) {
      throw new Error('Credenciais inválidas');
    }

    // Verificar senha
    const isValid = await this.verifyPassword(password, user.password);
    if (!isValid) {
      throw new Error('Credenciais inválidas');
    }

    // Gerar tokens
    const { access_token, refresh_token } = this.generateTokens(
      user.id,
      user.email,
      user.role
    );

    return {
      access_token,
      refresh_token,
      user: {
        id: user.id,
        email: user.email,
        firstName: user.firstName,
        lastName: user.lastName,
        role: user.role,
      },
    } as AuthResponse;
  }

  /**
   * Refresh access token
   */
  static refreshAccessToken(refreshToken: string) {
    const decoded = this.verifyToken(refreshToken);
    if (!decoded) {
      throw new Error('Token de refresh inválido');
    }

    const user = users.get(decoded.id);
    if (!user) {
      throw new Error('Usuário não encontrado');
    }

    const { access_token } = this.generateTokens(
      user.id,
      user.email,
      user.role
    );

    return { access_token };
  }

  /**
   * Obter dados do usuário pelo ID
   */
  static getUser(userId: string) {
    const user = users.get(userId);
    if (!user) {
      return null;
    }

    const { password, ...userWithoutPassword } = user;
    return userWithoutPassword;
  }
}

