import { Request, Response } from 'express';
import { AuthService } from '../services/auth.service';
import { RegisterSchema, LoginSchema } from '../schemas/auth.schema';

export class AuthController {
  /**
   * POST /api/v1/auth/register
   * Registrar novo usuário
   */
  static async register(req: Request, res: Response) {
    try {
      // Validar input
      const validData = RegisterSchema.parse(req.body);

      // Registrar usuário
      const result = await AuthService.register(validData);

      // Definir refresh token como HTTP-only cookie
      res.cookie('refreshToken', result.refresh_token, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'strict',
        maxAge: 7 * 24 * 60 * 60 * 1000, // 7 dias
      });

      res.status(201).json({
        message: 'Usuário registrado com sucesso',
        data: {
          access_token: result.access_token,
          user: result.user,
        },
      });
    } catch (error: any) {
      // Validação erro
      if (error.name === 'ZodError') {
        return res.status(400).json({
          error: 'Dados inválidos',
          details: error.errors,
        });
      }

      // Erro genérico
      res.status(400).json({ error: error.message });
    }
  }

  /**
   * POST /api/v1/auth/login
   * Fazer login
   */
  static async login(req: Request, res: Response) {
    try {
      // Validar input
      const validData = LoginSchema.parse(req.body);

      // Fazer login
      const result = await AuthService.login(validData);

      // Definir refresh token como HTTP-only cookie
      res.cookie('refreshToken', result.refresh_token, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'strict',
        maxAge: 7 * 24 * 60 * 60 * 1000, // 7 dias
      });

      res.status(200).json({
        message: 'Login bem-sucedido',
        data: {
          access_token: result.access_token,
          user: result.user,
        },
      });
    } catch (error: any) {
      if (error.name === 'ZodError') {
        return res.status(400).json({
          error: 'Dados inválidos',
          details: error.errors,
        });
      }

      res.status(401).json({ error: error.message });
    }
  }

  /**
   * POST /api/v1/auth/logout
   * Fazer logout
   */
  static logout(req: Request, res: Response) {
    try {
      // Limpar cookie de refresh token
      res.clearCookie('refreshToken');

      res.status(200).json({ message: 'Logout bem-sucedido' });
    } catch (error: any) {
      res.status(400).json({ error: error.message });
    }
  }

  /**
   * POST /api/v1/auth/refresh
   * Renovar access token
   */
  static refresh(req: Request, res: Response) {
    try {
      const refreshToken = req.cookies.refreshToken;
      if (!refreshToken) {
        return res.status(401).json({ error: 'Refresh token não fornecido' });
      }

      const result = AuthService.refreshAccessToken(refreshToken);

      res.status(200).json({
        message: 'Token renovado',
        data: result,
      });
    } catch (error: any) {
      res.status(401).json({ error: error.message });
    }
  }

  /**
   * GET /api/v1/auth/me
   * Obter informações do usuário autenticado (requer token)
   */
  static me(req: Request, res: Response) {
    try {
      if (!req.auth) {
        return res.status(401).json({ error: 'Não autenticado' });
      }

      const user = AuthService.getUser(req.auth.userId);
      if (!user) {
        return res.status(404).json({ error: 'Usuário não encontrado' });
      }

      res.status(200).json({
        data: user,
      });
    } catch (error: any) {
      res.status(400).json({ error: error.message });
    }
  }
}

